var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"이봐, 빨간 대가리. 도대체 그 침식체는 언제 잡으러 가는 거야?","JPN":"おい、赤髪さんよ。いったいいつになったら侵食体を狩りにいくんだ？","ENG":"Hey, redhead. When are you gonna go kill that C.O.?","TWN":"喂，紅頭髮的，到底什麼時候去逮那個侵蝕體？"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"당신은 뒤에서 손 놓고 있다가 보물만 쏙 빼 가려는 건 아니겠지?","JPN":"お前は後ろで傍観しながら、宝だけくすねる気じゃないだろうな？","ENG":"You're not thinking of taking all the rewards without lifting a finger, are ya?","TWN":"你該不會是想隔岸觀火，最後再搶冒出來功勞吧？"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"그런 낌새라도 보였다간 좋은 꼴 못 볼 거다.","JPN":"もしそんなそぶりを見せてみろ、痛い目に会うぞ。","ENG":"It won't end well for you if you try to pull a fast one on us.","TWN":"要是敢耍我們，我們可不會讓你好過。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"네 장기들이 각자 다른 대륙에서 숨 쉬게 해주지.","JPN":"お前の臓器を取り出して売ってやるからな。","ENG":"I'll carve you up and scatter your innards across all the continents.","TWN":"我會把你剁碎扔到海裡去餵魚。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"그럴 리가 있겠습니까? 이미 어떻게 녀석을 불러올지 다 생각을 해두었습니다.","JPN":"まさか、そんなことはしませんよ。すでに奴を誘い込む策は用意できています。","ENG":"I wouldn't dare think of doing that. Also, I have already thought of a plan to lure it out.","TWN":"怎麼可能？我已經想好要怎麼引出那傢伙。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"그리고 예전에도 말씀드렸다시피, 아티팩트는 먼저 줍는 자가 임자입니다.","JPN":"それに、前にもお伝えしましたが、アーティファクトは先に見つけた者勝ちです。","ENG":"And, as I have already mentioned before, the Artifact is anyone's game.","TWN":"而且就像我之前說，人造神器誰先撿到就是誰的。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"이 조잡한 무장들은 대체 뭐지?","JPN":"どの装備も粗末で話にならないな。","ENG":"What are all these crude weapons?","TWN":"這些劣質的武器是怎麼回事？"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"무슨 전쟁놀이라도 하러 가는 줄 아는 건가?","JPN":"戦争ごっこでもしに行くつもりなのか？","ENG":"Do they think we're going on a picnic or something?","TWN":"你們以為是在玩騎馬打仗嗎？"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"얼레? 이 누나 말하는 싸가지 좀 봐. 우리 메뚜기야 메뚜기. 못 들어봤어?","JPN":"あれぇ？　こら姉さん、口には気を付けようねえ。俺たちはバッタだぜ？　聞いたことあるだろう？","ENG":"Huh? Who does this girl think she is? We're the Grasshoppers. Haven't you ever heard of us?","TWN":"哎呀？這位姊姊你有沒有禮貌？我們可是蚱蜢幫欸，你沒聽說過我們的名號嗎？"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"지나가는 곳마다 사람이든 침식체든 싹싹 긁어먹는 새끼들이라고.","JPN":"俺たちは人だろうが侵食体だろうが、何でも骨の髄まで食らいつくすことで有名なんだぞ。","ENG":"We beat up every C.O. and human that we come across.","TWN":"無論走到哪裡，不管是人還是侵蝕體，都會被我們吃光抹淨。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"특히, 내 여자 친구 마리는 날아다니는 침식체를 단 한 번도 놓친 적이 없다고?","JPN":"中でも、俺のガールフレンドのマリは、飛び回る侵食体を取り逃したことは一度もないんだぜ？","ENG":"My darling, Marie, here has never let a single C.O. in the air get past us.","TWN":"而且，我的女朋友瑪麗從來沒有錯失過任何一隻飛行的侵蝕體。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"그렇지 자기?","JPN":"な？　ダーリン？","ENG":"Isn't that right, babe?","TWN":"我說的對吧，親愛的？"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"하아. 메뚜기든 여치든 그런 장비로는 놈의 갑피 하나 갉아 먹을 수 없다.","JPN":"はぁ、バッタなのかコオロギなのか知らんが、そんな装備では奴の甲皮には傷一つ付けられないぞ。","ENG":"Ugh. Grasshoppers or crickets, your gear won't even put a dent in its armor.","TWN":"哀，不管是蚱蜢還是蝗蟲，光憑這種裝備連它的殼都啃不動的。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"뭐야?! 지금 우리 마리가 침식체 갑피 하나 못 뚫는 고철이라는 거야?!","JPN":"何だと？　俺のマリが侵食体なんかに傷もつけられないへなちょこだとでも言うのか！！","ENG":"What?! Are you sayin' that my Marie is a piece of junk that can't even rip a hole in a C.O.'s armor?!","TWN":"什麼？！你說我的瑪麗是個連侵蝕體外殼都打不穿的廢鐵！？"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"어흐흑. 마리. 듣지 마. 네 이빨이 날카롭다는 건 오빠가 제일 잘 알고 있어!","JPN":"あんなの聞かなくてもいいんだよ、マリ。君の牙が鋭いのは、この俺が一番よくわかっているからな！","ENG":"Hngh... Oh, Marie. Don't listen to her. I know that your teeth are the sharpest in the world!","TWN":"嗚嗚嗚，瑪麗，別聽她胡說。你的牙齒有多鋒利，我是最清楚的！"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"당장 마리한테 사과해! 그렇지 않으면 그 쥐 파먹은 머리카락부터 잘근잘근 씹어줄 테니까!","JPN":"今すぐマリに謝れ！　じゃないとそのふさふさな髪の毛を噛みちぎってやるぞ！","ENG":"Apologize to Marie! If you don't, I'll make sure to rip your stray hair off first!","TWN":"立刻向瑪麗道歉！否則我就把你撕爛，就從你那頭像被老鼠啃過的頭髮開始！"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"한탕 두둑이 잡기 위해 특제 이터니움 탄환도 잔뜩 갖고 왔다.","JPN":"ここでがっぽり稼ぐために、特製エタニウム弾もめいっぱい持ってきた。","ENG":"I even brought a ton of special Eternium bullets to take down this thing.","TWN":"我想說可以大撈一筆，還特地帶來特製的永恆之金彈藥呢。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"메뚜기들 말고도 로터스 근처의 용병 집단들이 많이 모였어. 아주 이례적인 일이지.","JPN":"バッタ以外にも、ロータス周辺の傭兵集団は結構揃ってる。異例事態さ。","ENG":"A lot of other mercenaries from around Lotus, in addition to Grasshopper, are gathered here. Which is something you don't see often.","TWN":"不只是蚱蜢幫，還有很多洛德斯周圍厲害的傭兵團也都聚集在一起，這陣仗很罕見呢。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"물량으로 밀어붙인다면 못 할 것도 없다고 생각하는데.","JPN":"これだけの人数がいれば、なんとか押し切れると思うが。","ENG":"I thought that we could beat anything by outnumbering it.","TWN":"光是一人吐一口口水就可以淹死它吧？"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"물량으로 모든 게 해결이 되면 왜 개미는 아직도 인간을 지배하지 않는 건가?","JPN":"数がすべてを凌駕するのなら、アリがいまだ人間を支配していないのは何故だ？","ENG":"But if that's the case, why haven't ants dominated humans by now?","TWN":"如果數量能解決一切問題，那為什麼螞蟻還沒有統治人類？"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"이 새끼가 지금 뚫린 입이라고……!","JPN":"貴様、いい加減に……！","ENG":"You shut your pie hole...!","TWN":"瞧你牙尖嘴利的……！"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"다들 의욕이 넘치시는군요.","JPN":"皆さんやる気がみなぎっていますね。","ENG":"I see that everyone is full of energy.","TWN":"大家都很有活力呢。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"토벌대를 당장 해산시켜. 저 따위 오합지졸로 침식체를 잡을 수 없다.","JPN":"今すぐ討伐隊を解散させるんだ。あんな輩をいくら集めたところで、侵食体には勝てない。","ENG":"Disband your team. You won't be able to kill it with a ragtag group like this one.","TWN":"立刻解散討伐隊，那種烏合之眾根本無法對付侵蝕體。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"이들을 전부 사지로 이끌고 갈 생각인가?!","JPN":"彼らを皆死に追いやるつもりか！？","ENG":"Or are you planning to march them all to their deaths?!","TWN":"你是打算帶著他們去送死嗎？"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"한 합도 주고받지 못할 싸움을 할 생각은 없다.","JPN":"まともに立ち向かえないような戦いをするつもりはない。","ENG":"I don't plan on engaging in a fight where I can't even throw a jab at it.","TWN":"我不打算打沒有勝算的仗。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"이건…… 그저 불 속에 뛰어드는 벌레 떼나 다름없어.","JPN":"これでは……虫が火に飛び込むようなものだ。","ENG":"This is... no different than moths to a flame.","TWN":"這……根本就是飛蛾撲火，你們就是那群蛾。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"저들도 혹할 수 있는 방법을 마련했다고 하지 않았습니까?","JPN":"彼らが飛びつく説得材料を用意したと言いましたよね。","ENG":"Didn't I say I had a plan that would get their attention?","TWN":"我不是說過我有準備秘密武器嗎？"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"잠자코 지켜보시죠.","JPN":"もう少し見ていてください。","ENG":"Why don't you see that before jumping to conclusions?","TWN":"你就好好看著吧。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"뭐……?","JPN":"何……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"자, 그럼 여러분들에게 보여주기로 약속한 비밀 병기를 보여드리도록 하겠습니다.","JPN":"では、今からみなさんに、お見せすると約束していた秘密兵器を公開いたします。","ENG":"Now, allow me to show you the secret weapon I promised to unveil.","TWN":"好，那現在就讓大家看看我答應大家的密武器吧。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_NULL","text":{"KOREA":"우오오오오!!","JPN":"うおおおお！！","ENG":"Uwooooah!!","TWN":"喔喔喔喔！！"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_CHEER"},{"id":"L24_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"여러분이 보고 있는 이것은 구 관리국의 병기입니다.","JPN":"これらは、旧管理局が使っていた兵器です。","ENG":"What you are seeing right now is a weapon from the Old Administration.","TWN":"大家現在看到的是舊管理局的兵器。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_ADMIN_NULL_NULL","face":"UNIT_TOUCH"},"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"강인공지능을 탑재한 자주곡사포라고 이해하시면 될 겁니다.","JPN":"簡単に説明すると、高度な人工知能を搭載した、自走曲射砲になります。","ENG":"Think of it as a self-propelled howitzer equipped with a strong AI.","TWN":"你們可以把它當作是搭載人工智慧的自行曲射炮。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_ADMIN_NULL_NULL","face":"UNIT_TOUCH"},"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"저건……!","JPN":"あれは……！","ENG":"That's...!","TWN":"那是……！"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"저 자주곡사포, 본 적 있어!","JPN":"あの自走曲射砲……見たことあるぞ！","ENG":"I've seen that self-propelled howitzer before!","TWN":"我見過那個自行高射炮！"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"그로니아에서 한탕 하려고 들어와 있을 때, 한창 내전이 일어났을 때였거든.","JPN":"グロ二アで一儲けしてやろうとしていた頃、そこは内戦の真っただ中だった。","ENG":"When I went to Gronia to make a quick buck, a civil war was at full swing.","TWN":"我曾經去過格羅尼亞，想在那裡做個大買賣，那時正好是內戰時期。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"딱 한 번 본 것뿐이지만…… 땅바닥이 부글부글 끓어오르던 걸 잊을 수가 없지 뭐야?","JPN":"そこで一度見ただけだが……あの地面がブクブクと燃える光景は忘れられないぜ！","ENG":"I only saw one once, but... I can't forget how the ground was rumbling.","TWN":"雖然只見過一次……但我永遠無法忘記地面沸騰的景象。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"근데 저게 구 관리국의 병기라고? 그건 그냥 도시 전설 아니었어?","JPN":"あれが旧管理局の兵器だって？　単なる噂だと思っていたぞ。","ENG":"That's a weapon from the Old Administration? Isn't that just an urban legend?","TWN":"不過，你說那是舊管理局的兵器？那不是只是城市傳說嗎？"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"저걸 도대체 어떻게 입수한 거야, 빨간 대가리. 대단하잖아!","JPN":"どうやってそれを手に入れたんだ、赤髪さんよ。すげえぞ！","ENG":"How did you manage to get them, redhead? That's amazing!","TWN":"你到底是怎麼搞到手的？紅頭髮，有兩下子喔！"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"저만의 비밀 루트를 통해 가져왔다고만 말씀드리지요.","JPN":"私だけが知っている、秘密ルートを使ったとだけ言っておきます。","ENG":"Let's just say that I have a special route.","TWN":"我只能告訴你，我有自己的秘密管道。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"곡사포는 총 10문 정도 대기시켜 놨습니다.","JPN":"曲射砲は全部で10門ほど設置しています。","ENG":"I've placed a total of ten howitzers on standby.","TWN":"我已經預備好10座取射炮。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"이 곡사포가 뒤에서 포격을 시작한다면, 분명 그 침식체에게 유효한 타격을 줄 수 있을 테죠.","JPN":"この曲射砲で砲撃すれば、あの侵食体にもダメージを与えられるはずです。","ENG":"Once they start firing from the backlines, I'm sure we'll be able to land blows to even a C.O. of that size.","TWN":"一旦曲射炮從後方進行炮擊，肯定會對那個侵蝕體造成有效攻擊吧？"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"제가 말하지 않았습니까? 분명 마음에 드실 거라고요.","JPN":"どうですか？　気に入られる自信があったのですが。","ENG":"See? I told you that you'd like it.","TWN":"我不是說過你一定會滿意的。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"확실히…….","JPN":"確かに……","ENG":"You're right...","TWN":"確實……"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"저 병기의 위력이라면 그 고래에게 피해를 줄 수 있을지도 모르겠군.\xA0","JPN":"この兵器の威力なら、あのクジラにもダメージを与えることができるかもしれない。\xA0","ENG":"We might be able to cause some damage to that whale with weapons of this power.\xA0","TWN":"如果那個武器的威力，應該足以對那頭鯨魚造成傷害。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"하지만 모래 폭풍 속에서 그 녀석을 끌어내는 것이 먼저다.","JPN":"だが、まずは砂嵐の中から、奴を引きずり出すことが課題だ。","ENG":"But first, we must lure it out of the sandstorm.","TWN":"但首先要把那傢伙從沙塵暴中引出來。"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……놈을 불러올 방법은 준비해 두었겠지?","JPN":"……当然、その手立てはあるんだろうな？","ENG":"...I'm sure you also have a plan for that too, no?","TWN":"……你應該已經有準備好引出那傢伙的方法吧？"},"stage":{"bg":"COUNTRYROAD_TOWER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};